import React, {type FC} from "react";
import type {IKitsContainer} from "@lmb-it/kitsconcerto-types";
import {Text} from "../../../_compat";
import {isObject} from "lodash";
import {useKitsTheme} from "../../../contexts/Theme";

const ErrorMessage: FC<Omit<IKitsContainer, "id"> & { style?: Record<string, any> }> = ({ errors, invalid, style }) => {
    const {resolveToken} = useKitsTheme();
    const dangerColor = resolveToken('danger');

    if (!errors || !invalid) return null;

    const renderMessage = (message: string, key?: number) => (
        <Text key={key} p={0} m={0} mt={4} fontSize={12} fontColor={dangerColor} style={style}>
            {message}
        </Text>
    );

    if (typeof errors === "string") {
        return renderMessage(errors);
    }

    if (Array.isArray(errors)) {
        return (
            <>
                {errors.map((err, index) => renderMessage(err, index))}
            </>
        );
    }

    if (isObject(errors) && !("type" in errors)) {
        return (
            <>
                {Object.values(errors).map(
                    (err: any, i) =>
                        err?.message && renderMessage(err.message, i),
                )}
            </>
        );
    }

    return null;
};
export default ErrorMessage;
